const Q_PHYSICS_1998=[{"id": "objective>Physics>1998>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bullet fired at a wooden block of thickness 0.15m manages to penetrate the block. If the mass of the bullet is 0.025kg and the average resisting force of the wood is 7.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N, calculate the speed of the bullet just before it hits the wooden block.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">450ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">400ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">300ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">250ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = ma <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Therefore,</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />0.025</td></tr></table></div> <br/> a = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> using V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2ax; <br/> V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + (2 x 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> x 0.15) <br/> Therefore V = 300 m/s</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>1998>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of a sound wave at 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is 360ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Its velocity at 127<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120√3 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240√3 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">720√3 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">v ∝ &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 360m/s, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 + 273 = 300K, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 127 + 273 = 400K <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">360<hr size=\"1\" />v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">300<hr size=\"1\" />400</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">240&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>1998>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical quantity that has the same dimensions as impulse is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">momentum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface tension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impulse is the product of force and time, which is also equal to the change in momentum. Therefore, impulse and momentum have the same dimensions.</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>1998>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball is moving at 18ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in a direction inclined at 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal. The horizontal component to its velocity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9√3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6√3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8√3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">vcos&#952;</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18cos60</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18(0.5)</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9m/s</td></tr></table></div></div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>1998>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In free fall, a body of mass 1kg drops from a height of 125m from rest in 5s. How long will it take another body of mass 2kg to fall from rest from the same height?  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The time it takes for an object to fall from a certain height under the influence of gravity is independent of its mass. This is because the force of gravity acting on the object is proportional to its mass, and therefore the acceleration of the object due to gravity is constant (g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>). Therefore, a body of mass 2kg will take the same amount of time to fall from the same height as a body of mass 1kg, which is 5s.</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>1998>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball of mass 0.15kg is kicked against a rigid vertical wall with a horizontal velocity of 50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If it rebounced with a horizontal velocity of 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, Calculate the impulse of the ball on the ball · ·</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0Ns</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impulse = m(v-u) <br/> 0.15(50 - (-30)) <br/> 0.15 X 80 = 12Ns</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>1998>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force of attraction between two point masses is 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N when the distance between them is 0.18m. If the distance is reduced to 0.06m, calculate the force.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">∝</td><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(0.06)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(0.18)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>×0.18<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />0.06<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>1998>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform meter rule weighing 0.5N is to be pivoted on a knife-edge at the 30cm-mark. where will a force of 2N be placed from the pivot to balance the meter rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">95cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"1998/phy98q2.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Taking moment about P, <br/>  <br/> 2 &#215; x = 0.5 x (50 - 30) <br/> 2x = 10 <br/> x = 5 cm</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>1998>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man whose mass is 80kg climbs a staircase in 20s and expends power of 120W. Find the height of the staircase. <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.8m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pt = mgh <br/> 120 × 20 = 80(10)h <br/> 2400 = 800h <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2400<hr size=\"1\" />800</td></tr></table></div> <br/> h = 3m</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>1998>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A parachute attains a terminal velocity when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its density is equal to the density of air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the viscous force of the air and the upthrust completely counteract its weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it expands as a result of reduced external pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the viscous force of the air is equal to the sum of the weight and upthrust</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A parachute attains a terminal velocity when the viscous force of the air and the upthrust completely counteract its weight</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>1998>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a wheel and axle mechanism the diameters of the wheel and axle are 40cm and 8cm respectively. Given that the machine is 80% efficient, what effort is required to lift a load of 100N?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">workdone by hand<hr size=\"1\" />workdone by effort</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">80</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100×8<hr size=\"1\" />E×40</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> <br/>  <br/> E = 25N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>1998>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tendon in a man's leg is 0.01m long. If a force of 5N stretches the tendon by 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>m, calculate the strain on the muscle.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Strain is defined as the change in length divided by the original length. In this case, the change in length is 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>m and the original length is 0.01m. Therefore, the strain on the muscle is (2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>m) / 0.01m = 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. Therefore, the correct answer is option 3.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>1998>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these statements are correct for the pressures in liquids?  <br/> i. pressure in a liquid at a point acts equally in all directions. <br/> ii. pressure increases with depth.  <br/> iii. pressure at a depth depends on the shape of the container.  <br/> iv. pressure at the same depth in different liquids are proportional to the density at different liquids.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, iii, iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii, iii, iv only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statements are:  <br/> i. Pressure in a liquid at a point acts equally in all directions. This is known as Pascal's law.  <br/> ii. Pressure increases with depth. This is because the weight of the fluid above increases with depth, thus increasing the pressure.  <br/> iv. Pressure at the same depth in different liquids are proportional to the density of the liquids. This is because pressure is the product of the fluid's density, gravity, and depth. The shape of the container does not affect the pressure at a given depth, so statement iii is incorrect.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1998>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atmospheric pressure due to water is 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. What is the total pressure at the bottom of an ocean 10m deep?  <br/> [Density of water = 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure = hρg = 1000 x 10 x 10 = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Total pressure = (1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>) + (1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>) <br/> = 1.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE~~PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1998>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solid of weight 0.600N is totally immersed in oil and water respectively. If the upthrust of oil is 0.210N and the relative density of oil is 0.875. Find the upthrust in water.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.600N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.360N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.240N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.180N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Rd</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">upthrust in oil<hr size=\"1\" />upthrust in water</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.875</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.21<hr size=\"1\" />upthrust in water</td></tr></table></div> <br/> upthrust in water = 0.24N</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>1998>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A platinum resistance thermometer records 3.0Ω at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and 8.0Ω at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. If it records 6.0Ω in a certain environment, The temperature of the medium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">8Ω.....100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/>  <br/> 6Ω.....θ<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/>  <br/> 3Ω.....0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100-0<hr size=\"1\" />θ-0</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8-3<hr size=\"1\" />6-3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />3</td></tr></table></div> <br/> 5θ = 300 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td></tr></table></div></div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1998>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The linear expansivity of brass is 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If the volume of a piece of brass is 15.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, What is the volume at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16.03cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.09cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">linear</td><td style=\"text-align:center;\">expansivity</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>−V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>×Δθ</td></tr></table></div> <br/> Υ = 3α <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3×2</td><td style=\"text-align:center;\">*tmes*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-15<hr size=\"1\" />15(100-0)</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1500 × 6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> + 15 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.09 + 15 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 15.09cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>1998>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas has a volume of 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. If it is heated to temperature T until a final volume of 120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is attained, calculate T</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">87<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">114<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 + 273 = 300K <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">120<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">120(300)<hr size=\"1\" />100</td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 360K <br/> T = 360 - 273 = 87<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1998>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 500W heater is used to heat 0.6kg of water from 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C in t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> seconds. If another 1000W heater is used to heat 0.2kg of water from 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C in t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, seconds, find <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5<hr size=\"1\" />4</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />5</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pt = mc∆θ <br/> 500t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 0.6(100-25)c <br/> 1000t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.2(100-10)c <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90c<hr size=\"1\" />18c</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1998>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many grams of water at 17<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C must be added to 42g of ice at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to melt the ice completely?  <br/> [specific latent heat of fusion of ice = 3.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, specific heat capacity of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">320g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mL = mc∆θ <br/> 42 × 3.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> = m × 4200 × (17-0) <br/> 1.428 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span> = 71400m <br/> m = 200g</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>1998>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour is said to be saturated when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more molecules return to the liquid than the amount that left it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dynamic equilibrium exists between the molecules of the liquid and the vapour molecules at a given temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the vapour pressure is equal to the atmospheric pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all molecules are moving with the same speed in all directions at a given temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour is said to be saturated when a dynamic equilibrium exists between the molecules of the liquid and the vapour molecules at a given temperature</div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>1998>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One valid assumption of the kinetic theory of gasses is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the molecules of a gas are constantly in a state of motion and the number of collision remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of molecule of gas increases with increasing pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">as the temperature increases, the number of collision made by the gas molecule remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the molecules of gas are all identical and are very small in size</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the molecules of gas are all identical and are very small in size</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>1998>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical properties of sound waves can best be described by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection and diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization and reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization and diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization and refraction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sound waves are mechanical waves that travel through a medium (like air, water, or a solid material). They can be described by their properties of reflection and diffraction. Reflection of sound waves is the bouncing back of sound when it hits a hard surface. Diffraction is the bending of waves around small obstacles and the spreading out of waves beyond small openings. Polarization is a property of transverse waves (like light waves), not longitudinal waves like sound.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1998>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a closed organ pipe producing a musical note, an antinode will always be produced at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the closed end</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the open end</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the middle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all the parts of the pipe</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a closed organ pipe producing a musical note, an antinode will always be produced at the open end</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1998>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A steel wire of length 0.50m is stretched between two fixed points and its fundamental frequency is 200Hz. The speed of the wave in the wire is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">120ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">250ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In strings, λ = 2L <br/> V = Fλ <br/> V = 200 × 2 × 0.5 <br/> V = 200ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>1998>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a resonance tube experiment, if the fundamental frequency of the vibrating air column is 280Hz, the frequency of the third overtone is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">70Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">840Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1120Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1960Hz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a closed pipe: <br/>  <br/> 1st overtone = 3F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/> 2nd overtone = 5F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/> 3rd overtone = 7F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 7F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/>  <br/> = 7 x 280 <br/>  <br/> = 1960Hz</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1998>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object 0 lies at a distance m in front of concave mirror of focal length f. If m < f, then the final image obtained will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">virtual and diminished</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnified and erect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">real and inverted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminished and erect</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a concave mirror, when the object distance is less than the focal length, we have an image which is: <br/>  <br/> - Virtual <br/>  <br/> - Erect and  <br/>  <br/> - Magnified.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>1998>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed in front of two plane mirrors inclined at an angle of 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>. If the total number of images formed is 7, Find the value of θ</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">51<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />θ</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />θ</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">360<hr size=\"1\" />θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>1998>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable type of mirror used for the construction of the search light is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concave mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convex mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spherical mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> parabolic mirror</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A parabolic mirror is the most suitable for the construction of a searchlight. This is because a parabolic mirror can collect light from a source at its focus and reflect it in a parallel beam, which is ideal for a searchlight. A concave mirror would also produce a similar effect, but the beam would not be as parallel as with a parabolic mirror. Convex and spherical mirrors would disperse the light, which is not desirable for a searchlight.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>1998>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The displacement d produced in a glass block of thickness t and refractive index n when an object is viewed through it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> t – n</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">(1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />n</td><td style=\"text-align:center;\">)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">(1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />n</td><td style=\"text-align:center;\">)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">1<hr size=\"1\" />n</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1)</td></tr></table></div></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">real depth<hr size=\"1\" />apparent depth</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t<hr size=\"1\" />t-d</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t-d<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t<hr size=\"1\" />n</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t<hr size=\"1\" />n</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">t<hr size=\"1\" />n</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">t<hr size=\"1\" />n</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />n</td><td style=\"text-align:center;\">)</td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1998>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man wears convex lens glasses of focal length 30cm in order to correct his eye defect. instead of the optimum 25cm, his least distance of distinct vision is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">uv<hr size=\"1\" />u-v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">30</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25(-v)<hr size=\"1\" />25-(-v)</td></tr></table></div> <br/> 30(25+v) = -25v <br/> 750 + 30v = -25v <br/> -55v = 750 <br/> v = 14cm </div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1998>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are true about the infra-red radiation?  <br/> i. it is invisible  <br/> ii. it is called heat ray  <br/> iii. its frequency is higher than that of blue light  <br/> iv. it travels as a transverse wave</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, iii, iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii, iii, iv only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Infrared radiation is indeed invisible to the human eye and is often referred to as 'heat rays' due to its ability to cause heating effects. It also travels as a transverse wave like all electromagnetic waves. However, its frequency is lower than that of blue light, not higher. Blue light has a higher frequency and shorter wavelength than infrared radiation. Therefore, the correct options are i, ii, and iv.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>1998>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force of repulsion between two point positive charges 5μC and 8μC separated at a distance of 0.02 map art is.  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">1<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</td></tr></table></div></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">q1q2<hr size=\"1\" />r2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>×8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span><hr size=\"1\" />0.02×0.02</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">9</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span></td></tr></table></div> <br/> F = 900N</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>1998>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ebonite rod rubbed with fur attracts a glass rod rubbed with silk because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ebonite has a negative charge while glass has a positive charge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ebonite has a positive charge while glass has a negative charge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both have negative charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both have positive charges</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an ebonite rod is rubbed with fur, it gains electrons and becomes negatively charged. On the other hand, when a glass rod is rubbed with silk, it loses electrons and becomes positively charged. Therefore, they attract each other due to the principle that opposite charges attract.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>1998>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can be used to reduce local action in a Laclanche cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A carbon rod as the positive pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pure zinc as the negative pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium permanganate solution in contact with the positive pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">common salt solution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Local action in a Leclanche cell is caused by impurities in the zinc electrode, which cause it to react with the electrolyte even when the cell is not delivering current. This can be reduced by using pure zinc as the negative pole, which will not react with the electrolyte unless the cell is delivering current.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>1998>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the work done in moving a 2C charge between two points X and Y in an electric field if the potential difference is 100 volts</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work done in moving a charge in an electric field is given by the formula W = QV, where W is the work done, Q is the charge, and V is the potential difference. Substituting the given values, we get W = 2C * 100V = 200J.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1998>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A parallel plate capacitor has a common plate area of 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−8</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> and plate separation of 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m, Assuming free space, What is the capacitance?  <br/> [ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 9.0 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−12</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>N<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-16</span>F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-16</span>F</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>A<hr size=\"1\" />d</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−8</span>×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−12</span>×9<hr size=\"1\" />2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−3</span></td></tr></table></div> <br/> C = 22.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>F = 2.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-16</span>F</div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>1998>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The iron core of an induction coil is made from bundles of wire so as to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minimize eddy-currents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generate eddy-current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent sparking at the contact breaker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">get the greatest posible secondary voltage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To prevent eddy currents, which cause energy losses, the iron core is made of a bundle of parallel iron wires, individually coated with shellac to insulate them electrically. The eddy currents, which flow in loops in the core perpendicular to the magnetic axis, are blocked by the layers of insulation.</div>", "topic": "ELECTROMAGNETIC INDUCTION : EDDY CURRENT"}, {"id": "objective>Physics>1998>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electricity is supplied to a school along a cable of total resistance 0.5Ω with the maximum current drawn from the mains as 100A. The maximum energy dissipated as heat for 1 hr is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy dissipated as heat in a resistor is given by the formula E = I^2 * R * t, where I is the current, R is the resistance, and t is the time. Substituting the given values into the formula, we get E = (100)^2 * 0.5 * 3600 = 1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>J. Therefore, the correct answer is option 4.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1998>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transformer which can produce 8V from a 240v a.c. supply, has an efficiency of 80%. If the current in the secondary coil is 15A, calculate the current in the primary coil.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.625A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.600A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.500A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.250A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">η</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">80<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8×15<hr size=\"1\" />240×I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">8<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">120<hr size=\"1\" />240I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">8<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />16</td></tr></table></div> <br/> I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 0.625A</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>1998>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrochemical equivalent of a metal is 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kgC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The mass of the metal which 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C of electricity will deposit from a suitable electrolyte is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = QZ <br/>  <br/> = 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> x 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> <br/>  <br/> = 2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1998>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a nuclear fusion experiment, the loss of mass amounts to 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>kg. The amount of energy obtained from the fusion is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a nuclear fusion experiment, the energy obtained from the fusion is given by the product of the loss of mass and the square of the speed of light, according to Einstein's mass-energy equivalence principle. The speed of light is approximately 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s, so the energy obtained from the fusion is 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>kg * (3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s)^2 = 9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>J.</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>1998>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In photoelectric effect, electrons will leave the metal surface when illuminated by light of appropriate frequency if the photon energy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than the work function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the work function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the work function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the maximium kinetic energy of the electron</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the photoelectric effect, electrons are ejected from a metal surface when light of a certain frequency, known as the threshold frequency, shines on the surface. The energy of the photons in the light must be greater than the work function (the minimum energy required to remove an electron from the surface of the metal) for the photoelectric effect to occur. Therefore, the correct answer is 'greater than the work function'.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}, {"id": "objective>Physics>1998>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A body on the ground is acted on by a force of 10N at a point P as shown in the fig above. What force is needed to stop the body from moving eastwards? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5N in the direction of east</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N in the diretion of west</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>N in the direction of west</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10N in the southwest direction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The horizontal (eastward) component of the 10N force is = 10 cos60 <br/> → 10 x 0.5 = 5N.  <br/> The equilibrant force needed to stop the body moving eastward must act in exactly the <br/> opposite direction.  <br/> Therefore, the needed force is 5N in the direction of West</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>1998>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total resistance measured at PQ in the diagram above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2Ω, 2Ω and 2Ω are series <br/> sum of series resistance = 6Ω <br/> 6Ω and 3Ω are parallel <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">sum</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">parallel</td><td style=\"text-align:center;\">resistance</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6(3)<hr size=\"1\" />6+3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18<hr size=\"1\" />9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> 2Ω, 1Ω and 1Ω are series  <br/> total resistance = 2Ω + 1Ω + 1Ω = 4Ω</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>1998>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the AC circuit diagram above, the resonance frequency is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5000π Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2500π Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5000<hr size=\"1\" />π</td><td style=\"text-align:center;\">Hz</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2500<hr size=\"1\" />π</td><td style=\"text-align:center;\">Hz</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">LC&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>×8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2500<hr size=\"1\" />π</td><td style=\"text-align:center;\">Hz</td></tr></table></div></div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>1998>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrochemical equivalent of metal is 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kgC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The mass of the metal which 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C of  electricity will deposit from a suitable electrolyte </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.5x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.5x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = zQ <br/> m = 1.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> × 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> <br/> m = 2.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1998>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A  radioactive substance has a half-life of 80 days. If the initial number of atoms in the sample is 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>, how many atoms would remain at the end of 320 days?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.75 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.63 x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">320<hr size=\"1\" />80</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">fraction</td><td style=\"text-align:center;\">remaining</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">N</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span></td></tr></table></div> <br/> 3.75 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span></div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>1998>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a nuclear fusion experiment, the loss of mass amounts to 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>kg. The amount of energy obtained from the fusion is. <br/> [Speed of light = 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy obtained from the fusion can be calculated using Einstein's mass-energy equivalence principle, E=mc^2, where E is the energy, m is the mass, and c is the speed of light. Substituting the given values, E = (1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>kg) * (3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)^2 = 9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>J.</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}];
